// // This module captures the value of the D input on the falling edge of the clock and outputs it on the Q output.
module d_flip_flop(clk, D, Q);  

    input  clk;  
    input  D;  
    output  Q;  
    reg   Q;

    always @(posedge clk)
          begin
            Q <= D;
          end  

endmodule
